impl Solution { pub fn check_strings(black_s1: String, black_s2: String) -> bool { let black_f = |black_s: &str, black_p: usize| { let mut black_c = vec![0; 26]; black_s.bytes().enumerate().filter(|&(i, _)| i % 2 == black_p).for_each(|(_, b)| black_c[(b - b'a') as usize] += 1); black_c }; black_f(&black_s1, 0) == black_f(&black_s2, 0) && black_f(&black_s1, 1) == black_f(&black_s2, 1) } }